@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        return true
    }
    
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return false
        }
        
        handleUniversalLink(incomingURL)
        return true
    }
    
    private func handleUniversalLink(_ url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              components.host == "myapp.com",
              components.path == "/promo" else {
            return
        }
        
        PromoLinkHandler.shared.handlePromoLink(url: url)
    }
}

struct PromoCode: Codable {
    let code: String
    let discount: Int
    let appliedAt: Date
    
    var isValid: Bool {
        return discount > 0 && discount <= 100 && !code.isEmpty
    }
}

class PromoLinkHandler {
    static let shared = PromoLinkHandler()
    
    private let allowedHosts = ["myapp.com"]
    private let allowedPath = "/promo"
    private let maxDiscountPercentage = 100
    private let minDiscountPercentage = 0
    private let maxPromoCodeLength = 50
    
    private init() {}
    
    func handlePromoLink(url: URL) {
        guard validateURL(url) else {
            showError(message: "Invalid promotional link")
            return
        }
        
        guard let promoCode = extractPromoCode(from: url) else {
            showError(message: "Unable to extract promo code from link")
            return
        }
        
        guard promoCode.isValid else {
            showError(message: "Invalid promo code or discount value")
            return
        }
        
        applyPromoCode(promoCode)
    }
    
    private func validateURL(_ url: URL) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return false
        }
        
        guard let host = components.host, allowedHosts.contains(host) else {
            return false
        }
        
        guard components.path == allowedPath else {
            return false
        }
        
        guard components.scheme == "https" else {
            return false
        }
        
        return true
    }
    
    private func extractPromoCode(from url: URL) -> PromoCode? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            return nil
        }
        
        var code: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name {
            case "code":
                if let value = item.value {
                    code = sanitizePromoCode(value)
                }
            case "discount":
                if let value = item.value, let intValue = Int(value) {
                    discount = intValue
                }
            default:
                break
            }
        }
        
        guard let validCode = code,
              let validDiscount = discount,
              isValidPromoCode(validCode),
              isValidDiscount(validDiscount) else {
            return nil
        }
        
        return PromoCode(code: validCode, discount: validDiscount, appliedAt: Date())
    }
    
    private func sanitizePromoCode(_ code: String) -> String {
        let allowedCharacters = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-_"))
        let filtered = code.unicodeScalars.filter { allowedCharacters.contains($0) }
        let sanitized = String(String.UnicodeScalarView(filtered))
        return String(sanitized.prefix(maxPromoCodeLength))
    }
    
    private func isValidPromoCode(_ code: String) -> Bool {
        guard !code.isEmpty && code.count <= maxPromoCodeLength else {
            return false
        }
        
        let allowedCharacters = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-_"))
        return code.unicodeScalars.allSatisfy { allowedCharacters.contains($0) }
    }
    
    private func isValidDiscount(_ discount: Int) -> Bool {
        return discount > minDiscountPercentage && discount <= maxDiscountPercentage
    }
    
    private func applyPromoCode(_ promoCode: PromoCode) {
        guard UserAccountManager.shared.isUserLoggedIn() else {
            showLoginRequired(promoCode: promoCode)
            return
        }
        
        UserAccountManager.shared.applyPromoCode(promoCode) { success, error in
            DispatchQueue.main.async {
                if success {
                    self.showSuccess(promoCode: promoCode)
                } else {
                    self.showError(message: error ?? "Failed to apply promo code")
                }
            }
        }
    }
    
    private func showSuccess(promoCode: PromoCode) {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let rootViewController = windowScene.windows.first?.rootViewController else {
            return
        }
        
        let alert = UIAlertController(
            title: "Promo Code Applied!",
            message: "Your \(promoCode.discount)% discount has been applied successfully.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        rootViewController.present(alert, animated: true)
    }
    
    private func showError(message: String) {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let rootViewController = windowScene.windows.first?.rootViewController else {
            return
        }
        
        let alert = UIAlertController(
            title: "Error",
            message: message,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        rootViewController.present(alert, animated: true)
    }
    
    private func showLoginRequired(promoCode: PromoCode) {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let rootViewController = windowScene.windows.first?.rootViewController else {
            return
        }
        
        let alert = UIAlertController(
            title: "Login Required",
            message: "Please log in to apply this promo code.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Login", style: .default) { _ in
            PendingPromoCodeManager.shared.savePendingPromoCode(promoCode)
            self.navigateToLogin()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        rootViewController.present(alert, animated: true)
    }
    
    private func navigateToLogin() {
        NotificationCenter.default.post(name: .navigateToLogin, object: nil)
    }
}

class UserAccountManager {
    static let shared = UserAccountManager()
    
    private let userDefaults = UserDefaults.standard
    private let promoCodesKey = "appliedPromoCodes"
    private let isLoggedInKey = "isUserLoggedIn"
    
    private init() {}
    
    func isUserLoggedIn() -> Bool {
        return userDefaults.bool(forKey: isLoggedInKey)
    }
    
    func setUserLoggedIn(_ loggedIn: Bool) {
        userDefaults.set(loggedIn, forKey: isLoggedInKey)
    }
    
    func applyPromoCode(_ promoCode: PromoCode, completion: @escaping (Bool, String?) -> Void) {
        guard isUserLoggedIn() else {
            completion(false, "User not logged in")
            return
        }
        
        guard !hasPromoCodeBeenApplied(promoCode.code) else {
            completion(false, "This promo code has already been applied")
            return
        }
        
        validatePromoCodeWithServer(promoCode) { isValid, error in
            if isValid {
                self.savePromoCode(promoCode)
                completion(true, nil)
            } else {
                completion(false, error ?? "Invalid promo code")
            }
        }
    }
    
    private func validatePromoCodeWithServer(_ promoCode: PromoCode, completion: @escaping (Bool, String?) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) {
            completion(true, nil)
        }
    }
    
    private func hasPromoCodeBeenApplied(_ code: String) -> Bool {
        let appliedCodes = getAppliedPromoCodes()
        return appliedCodes.contains { $0.code == code }
    }
    
    private func savePromoCode(_ promoCode: PromoCode) {
        var appliedCodes = getAppliedPromoCodes()
        appliedCodes.append(promoCode)
        
        if let encoded = try? JSONEncoder().encode(appliedCodes) {
            userDefaults.set(encoded, forKey: promoCodesKey)
        }
    }
    
    func getAppliedPromoCodes() -> [PromoCode] {
        guard let data = userDefaults.data(forKey: promoCodesKey),
              let codes = try? JSONDecoder().decode([PromoCode].self, from: data) else {
            return []
        }
        return codes
    }
}

class PendingPromoCodeManager {
    static let shared = PendingPromoCodeManager()
    
    private let userDefaults = UserDefaults.standard
    private let pendingPromoCodeKey = "pendingPromoCode"
    
    private init() {}
    
    func savePendingPromoCode(_ promoCode: PromoCode) {
        if let encoded = try? JSONEncoder().encode(promoCode) {
            userDefaults.set(encoded, forKey: pendingPromoCodeKey)
        }
    }
    
    func getPendingPromoCode() -> PromoCode? {
        guard let data = userDefaults.data(forKey: pendingPromoCodeKey),
              let promoCode = try? JSONDecoder().decode(PromoCode.self, from: data) else {
            return nil
        }
        return promoCode
    }
    
    func clearPendingPromoCode() {
        userDefaults.removeObject(forKey: pendingPromoCodeKey)
    }
    
    func applyPendingPromoCodeIfExists() {
        guard let pendingPromoCode = getPendingPromoCode() else {
            return
        }
        
        PromoLinkHandler.shared.handlePromoLink(url: URL(string: "https://myapp.com/promo?code=\(pendingPromoCode.code)&discount=\(pendingPromoCode.discount)")!)
        clearPendingPromoCode()
    }
}

