        logoutButton.isHidden = !isLoggedIn
        
        appliedPromoCodes = UserAccountManager.shared.getAppliedPromoCodes()
        promoCodesTableView.reloadData()
    }
    
    @objc private func loginTapped() {
        UserAccountManager.shared.setUserLoggedIn(true)
        updateUI()
